2354	void SetupCollisionAABBs()
2355	{
2356	    g_CollisionAABBs.clear();
2357	    g_CollisionLines.clear();
2358	
2359	    // Espessura "fake" usada para dar volume às paredes/chão/teto no teste de colisão
2360	    const float wall_t = 0.1f;
2361	
2362	    // Limites das salas (x,z) e altura (y), conforme mapeamento da cena
2363	    const float sala1_min = -4.0f, sala1_max = 4.0f;
2364	    const float sala2_min = 4.2f,  sala2_max = 12.0f;
2365	    float s3_xmin = 6.0f, s3_xmax = 10.0f;
2366	    float s3_zmin = 6.2f, s3_zmax = 10.1f;
2367	    const float y_min = -1.0f, y_max = 3.0f;
2368	
2369	    // A porta entre a Sala 1 e a Sala 2 (centrada em Z = 0)
2370	    const float porta_z = 0.0f;
2371	    // A nova porta no final da Sala 2 (centrada em X = 8.0)
2372	    const float porta2_x = 8.0f; 
2373	    
2374	    const float porta_meia_largura = 0.6f; 
2375	    const float porta_topo_y = 0.5f;      
2376	
2377	    // Cria uma laje retangular de parede (AABB)
2378	    auto add_wall_slab = [&](float x_lo, float x_hi, float z_lo, float z_hi, float y_lo, float y_hi)
2379	    {
2380	        if (z_lo < z_hi && x_lo < x_hi)
2381	            g_CollisionAABBs.push_back({ glm::vec3(x_lo, y_lo, z_lo), glm::vec3(x_hi, y_hi, z_hi) });
2382	    };
2383	
2384	    // Corta um buraco em uma parede que corre paralela ao eixo Z
2385	    auto add_wall_with_doorway = [&](float x_lo, float x_hi, float z_lo, float z_hi)
2386	    {
2387	        add_wall_slab(x_lo, x_hi, z_lo, porta_z - porta_meia_largura, y_min, y_max);
2388	        add_wall_slab(x_lo, x_hi, porta_z + porta_meia_largura, z_hi, y_min, y_max);
2389	        add_wall_slab(x_lo, x_hi, porta_z - porta_meia_largura, porta_z + porta_meia_largura, porta_topo_y, y_max);
2390	    };
2391	
2392	    // Corta um buraco em uma parede que corre paralela ao eixo X (NOVO)
2393	    auto add_wall_with_doorway_z = [&](float x_lo, float x_hi, float z_lo, float z_hi)
2394	    {
2395	        add_wall_slab(x_lo, porta2_x - porta_meia_largura, z_lo, z_hi, y_min, y_max);
2396	        add_wall_slab(porta2_x + porta_meia_largura, x_hi, z_lo, z_hi, y_min, y_max);
2397	        add_wall_slab(porta2_x - porta_meia_largura, porta2_x + porta_meia_largura, z_lo, z_hi, porta_topo_y, y_max);
2398	    };
2399	
2400	    // Constrói a sala inteira. Adicionamos o parâmetro 'porta_em_z_max' com valor padrão 'false'.
2401	    auto add_room_aabbs = [&](float x_min, float x_max, float z_min, float z_max, bool porta_em_x_min, bool porta_em_x_max, bool porta_em_z_max = false)
2402	    {
2403	        // Chão e teto
2404	        add_wall_slab(x_min - wall_t, x_max + wall_t, z_min - wall_t, z_max + wall_t, y_min - wall_t, y_min);
2405	        add_wall_slab(x_min - wall_t, x_max + wall_t, z_min - wall_t, z_max + wall_t, y_max, y_max + wall_t);
2406	
2407	        // Parede em x = x_min
2408	        if (porta_em_x_min)
2409	            add_wall_with_doorway(x_min - wall_t, x_min, z_min - wall_t, z_max + wall_t);
2410	        else
2411	            add_wall_slab(x_min - wall_t, x_min, z_min - wall_t, z_max + wall_t, y_min, y_max);
2412	
2413	        // Parede em x = x_max
2414	        if (porta_em_x_max)
2415	            add_wall_with_doorway(x_max, x_max + wall_t, z_min - wall_t, z_max + wall_t);
2416	        else
2417	            add_wall_slab(x_max, x_max + wall_t, z_min - wall_t, z_max + wall_t, y_min, y_max);
2418	
2419	        // Parede em z = z_min (Fundos)
2420	        add_wall_slab(x_min - wall_t, x_max + wall_t, z_min - wall_t, z_min, y_min, y_max);
2421	        
2422	        // Parede em z = z_max (Frente)
2423	        if (porta_em_z_max)
2424	            add_wall_with_doorway_z(x_min - wall_t, x_max + wall_t, z_max, z_max + wall_t);
2425	        else
2426	            add_wall_slab(x_min - wall_t, x_max + wall_t, z_max, z_max + wall_t, y_min, y_max);
2427	    };
2428	
2429	    // Chão e teto físicos da Sala 3
2430	    add_wall_slab(s3_xmin - wall_t, s3_xmax + wall_t, s3_zmin - wall_t, s3_zmax + wall_t, y_min - wall_t, y_min);
2431	    add_wall_slab(s3_xmin - wall_t, s3_xmax + wall_t, s3_zmin - wall_t, s3_zmax + wall_t, y_max, y_max + wall_t);
2432	
2433	    // Parede Lateral Direita da Sala 3 (X = 6.0)
2434	    add_wall_slab(s3_xmin - wall_t, s3_xmin, s3_zmin - wall_t, s3_zmax + wall_t, y_min, y_max);
2435	
2436	    // Parede Lateral Esquerda da Sala 3 (X = 10.0)
2437	    add_wall_slab(s3_xmax, s3_xmax + wall_t, s3_zmin - wall_t, s3_zmax + wall_t, y_min, y_max);
2438	
2439	    // Parede da Frente da Sala 3 (Z = 10.1)
2440	    add_wall_slab(s3_xmin - wall_t, s3_xmax + wall_t, s3_zmax, s3_zmax + wall_t, y_min, y_max);
2441	
2442	    // Parede de Trás com Conexão/Porta da Sala 3 (Z = 6.2)
2443	    // Deixa o vão livre entre X = 7.4 e X = 8.6 para você passar vindo da Sala 2!
2444	    add_wall_slab(s3_xmin - wall_t, porta2_x - porta_meia_largura, s3_zmin - wall_t, s3_zmin, y_min, y_max);
2445	    add_wall_slab(porta2_x + porta_meia_largura, s3_xmax + wall_t, s3_zmin - wall_t, s3_zmin, y_min, y_max);
2446	    add_wall_slab(porta2_x - porta_meia_largura, porta2_x + porta_meia_largura, s3_zmin - wall_t, s3_zmin, porta_topo_y, y_max);
2447	
2448	    // Sala 1: x,z em [-4,+4] — porta na parede x=+4
2449	    add_room_aabbs(sala1_min, sala1_max, sala1_min, sala1_max, false, true);
2450	    
2451	    // Sala 2: x em [+4.2,+12], z em [-4,+6] — porta na parede x=+4.2 E porta na parede z=+6.0
2452	    // O último 'true' ativa o novo buraco que criamos!
2453	    add_room_aabbs(sala2_min, sala2_max, -4.0f, 6.0f, true, false, true);
2454	
2455	    // Paredes internas da Sala 1 ("prisão" central de vidro + parede sólida)
2456	    // Cada parede é um the_plane ([-1,1] em local) com as rotações aplicadas na renderização,
2457	    // resultando em lajes verticais de espessura wall_t centradas nas posições abaixo.
2458	    // Parede sólida em x=+1
2459	    g_CollisionAABBs.push_back({ glm::vec3(1.0f - wall_t, y_min, -1.0f), glm::vec3(1.0f + wall_t, y_max, 1.0f) });
2460	    // Parede de vidro em x=-1
2461	    g_CollisionAABBs.push_back({ glm::vec3(-1.0f - wall_t, y_min, -1.0f), glm::vec3(-1.0f + wall_t, y_max, 1.0f) });
2462	    // Parede de vidro em z=+1
2463	    g_CollisionAABBs.push_back({ glm::vec3(-1.0f, y_min, 1.0f - wall_t), glm::vec3(1.0f, y_max, 1.0f + wall_t) });
2464	    // Parede de vidro em z=-1
2465	    g_CollisionAABBs.push_back({ glm::vec3(-1.0f, y_min, -1.0f - wall_t), glm::vec3(1.0f, y_max, -1.0f + wall_t) });
2466	
2467	    // Botão: mesma matriz "model" usada para desenhá-lo (Matrix_Translate(9,-1,-1) * Matrix_Scale(1.65,1.65,1.65))
2468	    glm::mat4 model_button = Matrix_Translate(9.0f, -1.0f, -1.0f) * Matrix_Scale(1.65f, 1.65f, 1.65f);
2469	    g_CollisionAABBs.push_back(ComputeWorldAABB(g_VirtualScene["portal_button_reduced_2"].bbox_min, g_VirtualScene["portal_button_reduced_2"].bbox_max, model_button));
2470	
2471	    // Paredes Diagonais:
2472	    // Parede diagonal da Sala 2 (Centro: 11.0, -2.7 | Rotação: -45 graus | Escala: 2.0)
2473	    // Calculamos as extremidades aplicando o seno/cosseno de 45 graus (0.707) * escala (2.0) = 1.414
2474	    float offsetX = 1.414f;
2475	    float offsetZ = 1.414f;
2476	    
2477	    g_CollisionLines.push_back({
2478	        glm::vec2(11.0f - offsetX, -2.7f - offsetZ), // Ponto 1 (~ 9.586, -4.114)
2479	        glm::vec2(11.0f + offsetX, -2.7f + offsetZ), // Ponto 2 (~ 12.414, -1.286)
2480	        y_min,                                       // Chão (-1.0f)
2481	        y_max                                        // Teto (3.0f)
2482	    });
2483	
2484	    // Hitbox dinâmica da porta 2 (Fechada)
2485	    // Usamos 3.14159265f no lugar de M_PI pois a macro foi definida dentro do main
2486	    glm::mat4 model_door_closed = Matrix_Translate(8.0f, -1.0f, 6.1f) 
2487	                                * Matrix_Rotate_Y(3.14159265f) 
2488	                                * Matrix_Scale(1.5f, 1.5f, 1.5f);
2489	                                
2490	    g_ClosedDoorAABB = ComputeWorldAABB(
2491	        g_VirtualScene["portal_door_combined_model_1"].bbox_min, 
2492	        g_VirtualScene["portal_door_combined_model_1"].bbox_max, 
2493	        model_door_closed
2494	    );
2495	
2496	    // Hitboxes Físicas do Pilar e do Bolo (Sala 3)
2497	    // O pilar está centralizado em X=8.0 e Z=8.15.
2498	    // Com a escala de 0.2, os limites horizontais são exatamente:
2499	    // X: 8.0 - 0.2 até 8.0 + 0.2 (7.8f a 8.2f)
2500	    // Z: 8.15 - 0.2 até 8.15 + 0.2 (7.95f a 8.35f)
2501	    // E a altura vai do chão (-1.0f) até o topo do pilar (-0.2f)
2502	    g_CollisionAABBs.push_back({ 
2503	        glm::vec3(7.8f, -1.0f, 7.95f),  // Mínimo (X, Y, Z)
2504	        glm::vec3(8.2f, -0.2f, 8.35f)   // Máximo (X, Y, Z)
2505	    });
2506	
2507	    // O bolo está em cima do pilar (Y = -0.2f) com escala 0.1.
